/**
 * Generate a unique identifier based on current timestamp
 * Useful for creating unique test data that won't conflict
 *
 * @param prefix - Optional prefix for the identifier
 * @returns Unique string identifier
 */
function generateUniqueId(prefix = ''): string {
  const timestamp = Date.now();
  const random = Math.random().toString(36).substring(2, 8);
  return prefix ? `${prefix}-${timestamp}-${random}` : `${timestamp}-${random}`;
}

/**
 * Generate a random string of specified length
 *
 * @param length - Length of the string to generate
 * @param charset - Character set to use (default: alphanumeric)
 * @returns Random string
 */
function randomString(
  length: number,
  charset = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'
): string {
  let result = '';
  for (let i = 0; i < length; i++) {
    result += charset.charAt(Math.floor(Math.random() * charset.length));
  }
  return result;
}

/**
 * Generate a random integer between min and max (inclusive)
 *
 * @param min - Minimum value
 * @param max - Maximum value
 * @returns Random integer
 */
function randomInt(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

/**
 * Generate a random decimal with specified precision
 *
 * @param min - Minimum value
 * @param max - Maximum value
 * @param precision - Number of decimal places
 * @returns Random decimal number
 */
function randomDecimal(min: number, max: number, precision = 2): number {
  const value = Math.random() * (max - min) + min;
  const factor = Math.pow(10, precision);
  return Math.round(value * factor) / factor;
}

/**
 * Generate a random date within a range
 *
 * @param startDate - Start of the range
 * @param endDate - End of the range
 * @returns Random date as ISO string
 */
function randomDate(startDate: Date, endDate: Date): string {
  const start = startDate.getTime();
  const end = endDate.getTime();
  const randomTime = start + Math.random() * (end - start);
  return new Date(randomTime).toISOString().split('T')[0];
}

/**
 * Pick a random element from an array
 *
 * @param array - Array to pick from
 * @returns Random element
 */
function randomPick<T>(array: T[]): T {
  return array[Math.floor(Math.random() * array.length)];
}

